const body = $input.first().json.body;
let plan;
try {
  plan = typeof body.plan === 'string' ? JSON.parse(body.plan) : body.plan;
} catch (e) {
  throw new Error('Invalid plan JSON: ' + e.message);
}

const report_id = body.report_id || ('rpt_' + Date.now() + '_' + Math.random().toString(36).substring(2, 8));

const items = plan.steps.map(step => ({
  json: {
    report_id,
    plan_id: plan.plan_id || '',
    email: body.email,
    model: body.model || 'moonshotai/kimi-k2.5',
    total_steps: plan.total_steps || plan.steps.length,
    templateId: body.templateId || '',
    steps_only: body.steps_only === true,
    step: step
  }
}));

return items;

parameters.text:
=Execute the following analysis step.

REPORT ID: {{ $('Parse Plan & Generate Report ID').item.json.report_id }}
STEP: {{ $('Loop Over Steps').item.json.step.step_number }} of {{ $('Parse Plan & Generate Report ID').item.json.total_steps }}
PURPOSE: {{ $('Loop Over Steps').item.json.step.purpose }}
DATASET ID: {{ $('Loop Over Steps').item.json.step.dataset_id }}

VIEW: {{ $('Loop Over Steps').item.json.step.dataset_id ? 'n8n_data.v_ds_' + $('Loop Over Steps').item.json.step.dataset_id.replace(/-/g, '_') : 'N/A — aggregate step' }}
(Pre-built view with original column names — query directly, no WHERE clause needed)
TEMP TABLE (pre-materialized for this step): {{ $('Loop Over Steps').item.json.step.dataset_id ? 'n8n_data."tmp_' + $('Parse Plan & Generate Report ID').item.json.report_id.replace(/[^a-zA-Z0-9_]/g, '_') + '_step_' + $('Loop Over Steps').item.json.step.step_number + '"' : 'N/A — aggregate step' }}

DEPENDENCY TEMP TABLES: {{ $('Loop Over Steps').item.json.step.dependencies && $('Loop Over Steps').item.json.step.dependencies.length > 0 ? $('Loop Over Steps').item.json.step.dependencies.map(d => 'n8n_data."tmp_' + $('Parse Plan & Generate Report ID').item.json.report_id.replace(/[^a-zA-Z0-9_]/g, '_') + '_step_' + d + '"').join(', ') : 'None' }}

DEPENDENCY TEMP TABLE COLUMNS:
{{ $json.dep_column_info || 'None' }}


COLUMN TYPES:
{{ (() => { try { const raw = $('Fetch Column Mapping For Step').item.json.column_mapping; const mapping = typeof raw === 'string' ? JSON.parse(raw) : (raw || {}); const typeMap = { real: 'numeric', string: 'text', int: 'integer', date: 'date', bool: 'boolean' }; return Object.entries(mapping).map(([name, col]) => '"' + name + '" (' + (typeMap[col.replace(/\d+$/, '')] || 'text') + ')').join(', ') || '(aggregate step — no columns)'; } catch(e) { return '(types unavailable)'; } })() }}

QUERY: {{ $('Loop Over Steps').item.json.step.query_strategy.logic || 'standard query' }}

DEPENDENCIES: {{ $('Loop Over Steps').item.json.step.dependencies.join(', ') || 'None' }}
EXPECTED OUTPUT: {{ $('Loop Over Steps').item.json.step.expected_output.join(', ') }}

RULES:
1. SQL SAFETY CHECK (MANDATORY): If a SQL query is found in QUERY, you MUST validate and rewrite it to enforce these safety rules before passing it to the Query Dataset Tool:
   - Universal Numeric Cast: Any column being summed, averaged, or cast to numeric MUST use the exact format: NULLIF(TRIM(REPLACE("ColumnName"::text, ',', '')), '')::numeric
   - Universal Date Cast: Any date extraction MUST use: TO_DATE(NULLIF(TRIM("ColumnName"::text), ''), 'MM/DD/YY') (Adjust format as needed).
   - Safe Division: Every division operation MUST wrap the denominator in NULLIF(denominator, 0).
   - String Matching: Replace all strict '=' string comparisons with TRIM("ColumnName") ILIKE 'value'.
   - Anti-Double Counting: Ensure aggregations exclude totals using: TRIM("levels") NOT ILIKE '%Total%'.

2. Query step (dataset_id present): call Query Step Tables with SQL against TEMP TABLE above. Use GROUP BY/SUM/COUNT when possible. If asked for a full list run SELECT *. This is your only tool call.

3. Aggregate step WITH dependencies (DEPENDENCY TEMP TABLES listed above): call Query Step Tables with a multi-step CTE query. The dep tables contain RAW rows (not pre-aggregated) — you MUST aggregate within each dep table first (GROUP BY, SUM, RANK), then JOIN the results. Structure: WITH t1 AS (SELECT ... FROM dep_table_1 GROUP BY ...), t2 AS (...) SELECT ... FROM t1 FULL OUTER JOIN t2 ON ... This is your only tool call.

4. Aggregate step WITHOUT dependencies: call Read Previous Step Results for text summaries. This is your only tool call.

5. ERROR HANDLING: If the Query Dataset Tool returns a PostgreSQL syntax error, read the error message carefully. Identify if it was caused by dirty data (whitespace, uncast text, division by zero), apply the appropriate fix from Rule 1, and retry the tool call ONE more time.

6. After the ONE tool call returns successfully, immediately write your structured output and stop. Do not include suggested next steps or explain analysis process/method. Do not call any more tools.

