const items = $input.all();
if (items.length > 0 && items[0].json && items[0].json.dep_column_info !== undefined) {
  return [{ json: { dep_column_info: items[0].json.dep_column_info || 'None' } }];
}
const rows = items.filter(item => item.json && item.json.table_name);
const depColumnInfo = rows.length > 0
  ? rows.map(r => 'n8n_data."' + r.json.table_name + '": ' + r.json.columns).join('\n')
  : 'None';
return [{ json: { dep_column_info: depColumnInfo } }];

const items = $input.all();
if (!items || items.length === 0) {
  return [{ json: { output: 'No results returned.' } }];
}

const rows = items.map(i => i.json);
const headers = Object.keys(rows[0]);

// Build 10-row preview as markdown table
const headerRow = '| ' + headers.join(' | ') + ' |';
const separator = '| ' + headers.map(() => '---').join(' | ') + ' |';
const previewRows = rows.slice(0, 10).map(row =>
  '| ' + headers.map(h => {
    const val = row[h];
    return val === null || val === undefined ? '' : String(val).replace(/\|/g, '\\|');
  }).join(' | ') + ' |'
);
const preview = [headerRow, separator, ...previewRows].join('\n');
const previewNote = rows.length > 10
  ? `\n_Showing 10 of ${rows.length} rows — full data available as download_`
  : '';

// Build full CSV
const escapeCSV = v => {
  const s = String(v ?? '');
  if (s.includes(',') || s.includes('"') || s.includes('\n') || s.includes('\r')) {
    return '"' + s.replace(/"/g, '""') + '"';
  }
  return s;
};
const csvLines = [
  headers.map(escapeCSV).join(','),
  ...rows.map(row => headers.map(h => escapeCSV(row[h])).join(','))
];
const csvData = csvLines.join('\n');
const csvB64 = Buffer.from(csvData).toString('base64');

const output = `**Full List (${rows.length} rows)**\n\n${preview}${previewNote}\n<!--LIST_CSV:${csvB64}-->`;

return [{ json: { output } }];

const step = $('Loop Over Steps').item.json.step;
const reportId = $('Parse Plan & Generate Report ID').item.json.report_id.replace(/[^a-zA-Z0-9_]/g, '_');

let sql = (step.query_strategy && (step.query_strategy.sql || step.query_strategy.logic)) || 'SELECT 1';

// Replace stepN references with actual temp table names
sql = sql.replace(/\bstep(\d+)\b/gi, (match, num) => {
  return 'n8n_data."tmp_' + reportId + '_step_' + num + '"';
});

// Wrap in a subquery with a row cap to prevent unbounded result sets from timing out
const MAX_ROWS = 50000;
const hasLimit = /\bLIMIT\s+\d+/i.test(sql);
if (!hasLimit) {
  sql = 'SELECT * FROM (' + sql + ') AS _list_query LIMIT ' + MAX_ROWS;
}

return [{ json: { resolved_sql: sql } }];

const body = $input.first().json.body;
let plan;
try {
  plan = typeof body.plan === 'string' ? JSON.parse(body.plan) : body.plan;
} catch (e) {
  throw new Error('Invalid plan JSON: ' + e.message);
}

const report_id = body.report_id || ('rpt_' + Date.now() + '_' + Math.random().toString(36).substring(2, 8));

const items = plan.steps.map(step => ({
  json: {
    report_id,
    plan_id: plan.plan_id || '',
    email: body.email,
    model: body.model || 'moonshotai/kimi-k2.5',
    total_steps: plan.total_steps || plan.steps.length,
    templateId: body.templateId || '',
    steps_only: body.steps_only === true,
    step: step
  }
}));

return items;

